CREATE TYPE "AdminRole" AS ENUM ('superadmin', 'staff_admin', 'partner_admin');
CREATE TYPE "LicenseStatus" AS ENUM ('active', 'revoked', 'expired', 'disabled');
CREATE TYPE "ActivationKind" AS ENUM ('single', 'enterprise');
CREATE TYPE "TemplateState" AS ENUM ('draft', 'published', 'archived');

CREATE TABLE "Partner" ("id" TEXT NOT NULL, "name" TEXT NOT NULL, "email" TEXT, "notes" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Partner_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AdminUser" ("id" TEXT NOT NULL, "email" TEXT NOT NULL, "fullName" TEXT NOT NULL, "passwordHash" TEXT NOT NULL, "role" "AdminRole" NOT NULL DEFAULT 'staff_admin', "partnerId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "AdminUser_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ConfigProfile" ("id" TEXT NOT NULL, "name" TEXT NOT NULL, "description" TEXT, "speechProviderType" TEXT, "speechEndpointUrl" TEXT, "speechModelName" TEXT, "privacyControlEnabled" BOOLEAN NOT NULL DEFAULT false, "piiControlEnabled" BOOLEAN NOT NULL DEFAULT false, "presidioEndpointUrl" TEXT, "presidioSecretRef" TEXT, "privacyReviewProviderType" TEXT, "privacyReviewEndpointUrl" TEXT, "privacyReviewModel" TEXT, "documentGenerationProviderType" TEXT, "documentGenerationEndpointUrl" TEXT, "documentGenerationModel" TEXT, "templateRepositoryUrl" TEXT, "telemetryEndpointUrl" TEXT, "featureFlags" JSONB NOT NULL DEFAULT '{}', "allowedProviderRestrictions" JSONB NOT NULL DEFAULT '[]', "defaultTemplateId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "ConfigProfile_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Tenant" ("id" TEXT NOT NULL, "name" TEXT NOT NULL, "slug" TEXT NOT NULL, "partnerId" TEXT, "configProfileId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Tenant_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SingleLicenseKey" ("id" TEXT NOT NULL, "keyHash" TEXT NOT NULL, "keyPrefix" TEXT NOT NULL, "purchaserFullName" TEXT NOT NULL, "purchaserEmail" TEXT NOT NULL, "generatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "purchaseDate" TIMESTAMP(3), "activatedAt" TIMESTAMP(3), "expiresAt" TIMESTAMP(3), "deviceIdentifier" TEXT, "appVersion" TEXT, "lastCheckIn" TIMESTAMP(3), "status" "LicenseStatus" NOT NULL DEFAULT 'active', "notes" TEXT, "partnerId" TEXT, "createdByAdminId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "SingleLicenseKey_pkey" PRIMARY KEY ("id"));
CREATE TABLE "EnterpriseLicenseKey" ("id" TEXT NOT NULL, "keyHash" TEXT NOT NULL, "keyPrefix" TEXT NOT NULL, "tenantId" TEXT NOT NULL, "configProfileId" TEXT NOT NULL, "generatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3), "maxDevices" INTEGER, "status" "LicenseStatus" NOT NULL DEFAULT 'active', "notes" TEXT, "partnerId" TEXT, "createdByAdminId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "EnterpriseLicenseKey_pkey" PRIMARY KEY ("id"));
CREATE TABLE "DeviceActivation" ("id" TEXT NOT NULL, "kind" "ActivationKind" NOT NULL, "singleLicenseKeyId" TEXT, "enterpriseLicenseKeyId" TEXT, "tenantId" TEXT, "deviceIdentifier" TEXT NOT NULL, "activationTokenHash" TEXT NOT NULL, "appVersion" TEXT NOT NULL, "activatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "lastCheckIn" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "status" "LicenseStatus" NOT NULL DEFAULT 'active', "metadata" JSONB NOT NULL DEFAULT '{}', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "DeviceActivation_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ActivationAuditLog" ("id" TEXT NOT NULL, "actorAdminId" TEXT, "actorEmail" TEXT, "action" TEXT NOT NULL, "targetType" TEXT NOT NULL, "targetId" TEXT, "ipAddress" TEXT, "userAgent" TEXT, "metadata" JSONB NOT NULL DEFAULT '{}', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "ActivationAuditLog_pkey" PRIMARY KEY ("id"));
CREATE TABLE "TemplateCategory" ("id" TEXT NOT NULL, "slug" TEXT NOT NULL, "title" TEXT NOT NULL, "description" TEXT, CONSTRAINT "TemplateCategory_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Template" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "shortDescription" TEXT NOT NULL, "categoryId" TEXT, "language" TEXT NOT NULL, "icon" TEXT NOT NULL, "tags" JSONB NOT NULL DEFAULT '[]', "tenantId" TEXT, "state" "TemplateState" NOT NULL DEFAULT 'draft', "publishedVersionId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Template_pkey" PRIMARY KEY ("id"));
CREATE TABLE "TemplateVersion" ("id" TEXT NOT NULL, "templateId" TEXT NOT NULL, "version" TEXT NOT NULL, "yamlContent" TEXT NOT NULL, "state" "TemplateState" NOT NULL DEFAULT 'draft', "createdByAdminId" TEXT, "publishedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "TemplateVersion_pkey" PRIMARY KEY ("id"));

CREATE UNIQUE INDEX "AdminUser_email_key" ON "AdminUser"("email");
CREATE UNIQUE INDEX "Tenant_slug_key" ON "Tenant"("slug");
CREATE UNIQUE INDEX "SingleLicenseKey_keyHash_key" ON "SingleLicenseKey"("keyHash");
CREATE UNIQUE INDEX "EnterpriseLicenseKey_keyHash_key" ON "EnterpriseLicenseKey"("keyHash");
CREATE UNIQUE INDEX "DeviceActivation_activationTokenHash_key" ON "DeviceActivation"("activationTokenHash");
CREATE UNIQUE INDEX "DeviceActivation_singleLicenseKeyId_deviceIdentifier_key" ON "DeviceActivation"("singleLicenseKeyId", "deviceIdentifier");
CREATE UNIQUE INDEX "DeviceActivation_enterpriseLicenseKeyId_deviceIdentifier_key" ON "DeviceActivation"("enterpriseLicenseKeyId", "deviceIdentifier");
CREATE UNIQUE INDEX "TemplateCategory_slug_key" ON "TemplateCategory"("slug");
CREATE UNIQUE INDEX "TemplateVersion_templateId_version_key" ON "TemplateVersion"("templateId", "version");

ALTER TABLE "AdminUser" ADD CONSTRAINT "AdminUser_partnerId_fkey" FOREIGN KEY ("partnerId") REFERENCES "Partner"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Tenant" ADD CONSTRAINT "Tenant_partnerId_fkey" FOREIGN KEY ("partnerId") REFERENCES "Partner"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Tenant" ADD CONSTRAINT "Tenant_configProfileId_fkey" FOREIGN KEY ("configProfileId") REFERENCES "ConfigProfile"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "SingleLicenseKey" ADD CONSTRAINT "SingleLicenseKey_partnerId_fkey" FOREIGN KEY ("partnerId") REFERENCES "Partner"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "EnterpriseLicenseKey" ADD CONSTRAINT "EnterpriseLicenseKey_tenantId_fkey" FOREIGN KEY ("tenantId") REFERENCES "Tenant"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "EnterpriseLicenseKey" ADD CONSTRAINT "EnterpriseLicenseKey_configProfileId_fkey" FOREIGN KEY ("configProfileId") REFERENCES "ConfigProfile"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "EnterpriseLicenseKey" ADD CONSTRAINT "EnterpriseLicenseKey_partnerId_fkey" FOREIGN KEY ("partnerId") REFERENCES "Partner"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "DeviceActivation" ADD CONSTRAINT "DeviceActivation_singleLicenseKeyId_fkey" FOREIGN KEY ("singleLicenseKeyId") REFERENCES "SingleLicenseKey"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "DeviceActivation" ADD CONSTRAINT "DeviceActivation_enterpriseLicenseKeyId_fkey" FOREIGN KEY ("enterpriseLicenseKeyId") REFERENCES "EnterpriseLicenseKey"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "DeviceActivation" ADD CONSTRAINT "DeviceActivation_tenantId_fkey" FOREIGN KEY ("tenantId") REFERENCES "Tenant"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Template" ADD CONSTRAINT "Template_categoryId_fkey" FOREIGN KEY ("categoryId") REFERENCES "TemplateCategory"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Template" ADD CONSTRAINT "Template_tenantId_fkey" FOREIGN KEY ("tenantId") REFERENCES "Tenant"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "TemplateVersion" ADD CONSTRAINT "TemplateVersion_templateId_fkey" FOREIGN KEY ("templateId") REFERENCES "Template"("id") ON DELETE CASCADE ON UPDATE CASCADE;
